VALUES
  ('optometrist-moex-02434', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '硬式隱形眼鏡試片度數-4.00 DS、基弧7.65 mm、鏡片光學區8.0 mm、鏡片總直徑9.4 mm，而戴鏡驗光 最佳視力1.0的度數為-2.00 DS，頂點距離12.5 mm。基弧若想改為7.75 mm，則屈光度數應改為多少？', '["-5.25 DS", "-5.50 DS", "-6.25 DS", "-6.50 DS"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "879d402a916a", "answer_pdf_sha1": "60102628a2c1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02435', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '驗配高透氧硬式隱形眼鏡，有診斷法（diagnostic fitting）與經驗法（empirical fitting）兩種方式，比較此 兩種方式，診斷法的優點為：', '["更好的配戴者滿意度與順從性", "較簡單，但必須收集病患更多的參數資料", "通常透過角膜地圖儀軟體來設計所需要鏡片", "檢查少，因此一開始比較不花費驗配者的時間"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "879d402a916a", "answer_pdf_sha1": "60102628a2c1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02436', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關理想的硬式透氧隱形眼鏡配戴，下列敘述何者正確？', '["螢光染色不見中心間隙", "螢光染色不見邊緣間隙", "往任何方向看，鏡片皆完全在角膜緣之內", "眨眼時鏡片上下滑動小於1 mm"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "879d402a916a", "answer_pdf_sha1": "60102628a2c1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02437', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '根據Nathan Efron教科書，軟式隱形眼鏡鏡片驗配的眨眼後鏡片最理想滑動量應為多少？', '["0-0.2 mm", "0.2-0.4 mm", "0.6-0.9 mm", "1.0-1.2 mm"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "879d402a916a", "answer_pdf_sha1": "60102628a2c1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02438', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關角膜地圖儀，下列敘述何者錯誤？', '["角膜地圖儀與角膜弧度儀比較，測量涵蓋較大的角膜區塊，以及角膜的形狀", "在角膜地圖儀上，若頂點的屈光度大於47 D以上，或者中央3 mm鼻顳側的屈光度相差1.50 D以上， 就要懷疑可能有圓錐角膜", "切線圖（tangential map）是根據角膜每個點的弧度來呈現，提供較完整的角膜形狀，能偵測出角膜局部 細微的變化，顯示出真正的角膜頂點", "軸向圖（axial map），是參考患者的視軸（visual axis）計算出各點的屈率而形成"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "879d402a916a", "answer_pdf_sha1": "60102628a2c1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02439', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '以細隙燈觀察，下列何者不是因為長期配戴隱形眼鏡所造成？', '["上眼瞼結膜出現乳突狀（papillary）結膜炎", "角膜水腫比較嚴重（grade 3以上）時，可看到基質皺褶（stromal fold）", "角膜上輪部角膜炎（superior limbic keratitis）", "在3點及9點的方向，可看到結膜裂斑（pinguecula）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "879d402a916a", "answer_pdf_sha1": "60102628a2c1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02440', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關配戴隱形眼鏡造成角膜的反應，下列敘述何者正確？', '["隱形眼鏡清潔液所造成的敏感發炎反應會直接傷害到角膜內皮細胞", "角膜內皮細胞隨著年紀增長數量會增加，內皮細胞變異性（polymegethism）則會減少", "角膜內皮細胞受傷凋亡後可以像表皮細胞一樣再生", "配戴隱形眼鏡引起的角膜缺氧可能會造成內皮細胞空泡（bleb）或內皮細胞變異性會增加"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "879d402a916a", "answer_pdf_sha1": "60102628a2c1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02441', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關隱形眼鏡引起的角膜新生血管或血管翳的敘述，下列何者錯誤？', '["以深層的新生血管最常見", "初期通常不會影響視力", "血管翳（pannus）通常發生在角膜的上方", "血管翳分成發炎性（inflammatory）及退化性（degenerative）兩種"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "879d402a916a", "answer_pdf_sha1": "60102628a2c1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02442', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '戴了軟式隱形眼鏡之後立即覺得灼熱感（burning），最常見的原因為何？', '["灰塵跑入隱形眼鏡", "化妝品顆粒跑入隱形眼鏡", "對隱形眼鏡的溶液過敏", "隱形眼鏡太緊"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "879d402a916a", "answer_pdf_sha1": "60102628a2c1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02443', 'optometrist', 'optometrist-moex-108-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關巨大乳突結膜炎（giant papillary conjunctivitis）的敘述，下列何者錯誤？', '["配戴軟式或硬式隱形眼鏡都有可能發生", "通常軟式隱形眼鏡配戴者會較硬式隱形眼鏡配戴者較快發生", "軟式隱形眼鏡造成的乳突通常最早發生在Allansmith分類瞼結膜之第三區（zone 3）", "軟式隱形眼鏡的材質以silicone的材質最容易發生"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:52+00:00", "source_pdf_sha1": "879d402a916a", "answer_pdf_sha1": "60102628a2c1", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
